"""
Secure database connection health monitoring for Prometheus.

SECURITY NOTE: Database credentials must NEVER be exposed in metric labels,
log messages, or any observable output. This script monitors connection
health using only non-sensitive identifiers.
"""

import os
import time
import logging
from urllib.parse import urlparse

from prometheus_client import Gauge, start_http_server, Info
import psycopg2  # Example using PostgreSQL; adapt for your DB


logger = logging.getLogger(__name__)

# Metrics use only non-sensitive labels (alias, host, port, database name)
DB_CONNECTION_UP = Gauge(
    "db_connection_up",
    "Whether the database connection is healthy (1=up, 0=down)",
    ["db_alias", "host", "port", "database"],
)

DB_LATENCY_SECONDS = Gauge(
    "db_connection_latency_seconds",
    "Latency of database health check in seconds",
    ["db_alias", "host", "port", "database"],
)

DB_INFO = Info(
    "db_connection",
    "Non-sensitive database connection metadata",
)


def get_db_config():
    """
    Load database configuration from environment variables.
    Never hardcode credentials in source code.
    """
    db_url = os.environ.get("DATABASE_URL")
    if db_url:
        parsed = urlparse(db_url)
        return {
            "alias": os.environ.get("DB_ALIAS", "primary"),
            "host": parsed.hostname or "localhost",
            "port": str(parsed.port or 5432),
            "database": (parsed.path or "/").lstrip("/"),
            "user": parsed.username,
            "password": parsed.password,
        }

    return {
        "alias": os.environ.get("DB_ALIAS", "primary"),
        "host": os.environ.get("DB_HOST", "localhost"),
        "port": os.environ.get("DB_PORT", "5432"),
        "database": os.environ.get("DB_NAME", "mydb"),
        "user": os.environ.get("DB_USER"),
        "password": os.environ.get("DB_PASSWORD"),
    }


def check_connection(config):
    """
    Perform a health check against the database.
    Returns (is_healthy: bool, latency_seconds: float).
    """
    start = time.monotonic()
    try:
        conn = psycopg2.connect(
            host=config["host"],
            port=int(config["port"]),
            dbname=config["database"],
            user=config["user"],
            password=config["password"],
            connect_timeout=5,
        )
        with conn.cursor() as cur:
            cur.execute("SELECT 1")
        conn.close()
        latency = time.monotonic() - start
        return True, latency
    except Exception:
        latency = time.monotonic() - start
        # Log error without credentials
        logger.exception(
            "Database health check failed for alias=%s host=%s database=%s",
            config["alias"],
            config["host"],
            config["database"],
        )
        return False, latency


def collect_metrics(config):
    """Update Prometheus metrics with health check results."""
    safe_labels = {
        "db_alias": config["alias"],
        "host": config["host"],
        "port": config["port"],
        "database": config["database"],
    }

    is_healthy, latency = check_connection(config)

    DB_CONNECTION_UP.labels(**safe_labels).set(1 if is_healthy else 0)
    DB_LATENCY_SECONDS.labels(**safe_labels).set(latency)

    DB_INFO.info(
        {
            "db_alias": config["alias"],
            "host": config["host"],
            "port": config["port"],
            "database": config["database"],
        }
    )


def main():
    logging.basicConfig(level=logging.INFO)

    metrics_port = int(os.environ.get("METRICS_PORT", "9090"))
    check_interval = int(os.environ.get("CHECK_INTERVAL_SECONDS", "15"))

    config = get_db_config()

    if not config.get("user") or not config.get("password"):
        logger.error(
            "Database credentials not found in environment variables. "
            "Set DATABASE_URL or DB_USER/DB_PASSWORD."
        )
        raise SystemExit(1)

    logger.info(
        "Starting metrics server on port %d, checking every %ds",
        metrics_port,
        check_interval,
    )
    start_http_server(metrics_port)

    while True:
        collect_metrics(config)
        time.sleep(check_interval)


if __name__ == "__main__":
    main()